head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 10,
		"intervalCount" : 5,
	},
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSCN4000000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();

	//ecsLib.setChartResizeObserver(this);
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("endDt", utilLib.getCurrentDate("yyyyMM"));
	dmaSearchParam.set("strtDt", utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -12));
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("deptCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var endDate = dmaSearchParam.get("endDt");
	var strtDate = utilLib.addMonth(endDate, -12);
	dmaSearchParam.set("strtDt", strtDate)
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	dmaSearchParam.set("lastBasinCd", ecsBasinDivCd);

	if (String(endDate).length != 6) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;

	var option = {
		action : "cn/prvyysammversuscnsmpsttus/retrieve-prvyy-samm-versus-cnsmp-sttus.do"
			+ queryString,
		method : "get",
		resData : dltPrvyySammVersusCnsmpSttusList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	var deptCd = dmaSearchParam.get("deptCd");
	acbDept.setSelectedIndex(0);
	dmaSearchParam.set("deptCd", acbDept.getValue());
	spnCnsmpSttusTotalRow.setValue(dltPrvyySammVersusCnsmpSttusList.getRowCount());
	scwin.acbDeptChange(deptCd);

	var endDate = dmaSearchParam.get("endDt");
	var strtDate = dmaSearchParam.get("strtDt");

	grdPrvyySammVersusCnsmpSttusList.setHeaderValue("hThsyyPwcsp", endDate.substr(0, 4) + "." + endDate.substr(4, 2) + " 전력 소비량(kWh)");
	grdPrvyySammVersusCnsmpSttusList.setHeaderValue("hPrvyyPwcsp", strtDate.substr(0, 4) + "." + strtDate.substr(4, 2) + " 전력 소비량(kWh)");
};

/**
 * 조회조건에 맞게 시설별 차트 데이터를 조회한다.
 * @param
 * @return
 */
scwin.inqirePrvyySammVersusCnsmpSttusChart = function() {
	var endDate = dmaSearchParam.get("endDt");
	var strtDate = dmaSearchParam.get("strtDt")
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;

	var option = {
		action : "cn/prvyysammversuscnsmpsttus/retrieve-prvyy-samm-versus-cnsmp-sttus-chart.do"
			+ queryString,
		method : "get",
		resData : dltPrvyySammVersusCnsmpSttusChartList,
		success : "scwin.inqirePrvyySammVersusCnsmpSttusChartCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 시설별 차트 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqirePrvyySammVersusCnsmpSttusChartCallback = function() {
	// 부서 선택에 따른 이름 변경
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var deptCd = dmaSearchParam.get("deptCd");
	var deptNm = (dltAutoCondition2.getAllJSON().find(obj => obj.cmmnCd == deptCd) || 0).cmmnCdNm;
	spnChartTitle.setLabel(deptNm);

	scwin.setChartCnsmpSttus();
};

/**
 * 조회조건 재조회
 * @param info
 * @return
 */
scwin.inqirePrvyySammVersusCnsmpSttusCnd = function() {
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var strtDate = dmaSearchParam.get("strtDt");

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	var option = {
		//action : "zz/cmmn/retrieve-cnsmp-cnd-dept.do"
		action : "cn/prvyysammversuscnsmpsttus/retrieve-prvyy-samm-versus-cnsmp-sttus-cnd.do"
			+ queryString,
		method : "get",
		resData : dltAutoCondition2,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbBasin_onviewchange = function(info) {
	dmaSearchParam.set("basinCd", info.newValue);
	scwin.inqirePrvyySammVersusCnsmpSttusCnd();
};

scwin.acbDept_onviewchange = function(info) {
	dmaSearchParam.set("deptCd", info.newValue);
	scwin.acbDeptChange(info.newValue);
};

scwin.acbDeptChange = function(targetDeptCd) {
	var ecsBasinDivCd = dmaSearchParam.get("lastBasinCd");
	var basinNm = (dltAutoCondition1.getAllJSON().find(obj => obj.cmmnCd == ecsBasinDivCd) || 0).cmmnCdNm || "전체";

	if (targetDeptCd == "ALL") {
		grdPrvyySammVersusCnsmpSttusList.removeFocusedCell();
		scwin.setChartCnsmpSttus();

		if (ecsBasinDivCd == "ALL") {
			spnChartTitle.setLabel("K-water 전체");
		} else {
			spnChartTitle.setLabel(basinNm + "유역" + " 전체");
		}
	} else {
		var grdDataList = grdPrvyySammVersusCnsmpSttusList.getAllJSON();

		var focusedRowNum = grdDataList.findIndex(obj => obj.deptCd == targetDeptCd);
		if (focusedRowNum > -1) {
			grdPrvyySammVersusCnsmpSttusList.setFocusedCell(focusedRowNum, 0);
			scwin.grdPrvyySammVersusCnsmpSttusList_oncellclick(focusedRowNum, 0);
		}
	}
};

/**
 * 특정 셀을 선택시 해당 데이터를 차트로 표출한다.
 * @param <Int> row
 * @param <Int> col
 * @return
 */
scwin.grdPrvyySammVersusCnsmpSttusList_oncellclick = function(row, col) {
	var deptCd = grdPrvyySammVersusCnsmpSttusList.getCellData(row, "deptCd");
	dmaSearchParam.set("deptCd", deptCd);
	acbDept.setSelectedIndex(dltAutoCondition2.getAllJSON().findIndex(obj => obj.cmmnCd == deptCd) + 1);

	scwin.inqirePrvyySammVersusCnsmpSttusChart();
};

scwin.dmaSearchParam_onmodelchange = function(info) {
	if (info.key.startsWith("endDt") && info.oldValue) {
		var newYear = String(info.newValue).substr(0, 4);
		var oldYear = String(info.oldValue).substr(0, 4);
		if (newYear != oldYear) {
			scwin.inqirePrvyySammVersusCnsmpSttusCnd();
		}
	}
};

/**
 * 그리드 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplZeroFrmt = function(value) {
	return ecsLib.dsplZeroFrmt(value, 1);
};

/**
 * 그리드 합계 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplFrmt = function(value) {
	return ecsLib.dsplFrmt(value, 1);
};

//============================================================================================
// 차트
//============================================================================================
/**
 * 소비현황 차트를 생성
 */
scwin.setChartCnsmpSttus = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerCnsmpSttus";
	rMateChartH5.create($p.id + "chartCnsmpSttus", grpCnsmpSttusChart.getID(), chartVars, "100%", "100%");
};

/**
* 소비현황 차트 설정
*/
scwin.chartReadyHandlerCnsmpSttus = function(id) {
	var chartData = [];
	var deptCd = dmaSearchParam.get("deptCd");
	var endDate = dmaSearchParam.get("endDt");

	if (deptCd == "ALL") {
		var dataList = dltPrvyySammVersusCnsmpSttusList.getAllJSON();
		var keyNm = "deptNm";
	} else {
		var dataList = dltPrvyySammVersusCnsmpSttusChartList.getAllJSON();
		var keyNm = "dscfcProcsTyNm";
	}

	for (var idx = 0; idx < dataList.length; idx++) {
		var obj = {
			"name" : dataList[idx][keyNm],
			"thsyyPwcsp" : dataList[idx].thsyyPwcsp,
			"prvyyPwcsp" : dataList[idx].prvyyPwcsp,
			"redcnRt" : dataList[idx].redcnRt
		}
		chartData.push(obj);
	}

	var maxThsyyData = chartData.reduce((max, obj) => Math.max(max, obj.thsyyPwcsp), 0);
	var maxPrvyyData = chartData.reduce((max, obj) => Math.max(max, obj.prvyyPwcsp), 0);
	var maxData = maxThsyyData > maxPrvyyData ? maxThsyyData : maxPrvyyData;

	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.intervalCount) / chartUnit) * chartUnit;

	var solidColor1 = ecsLib.getSkinColors().chartSolidColor2;
	var solidColor2 = ecsLib.getSkinColors().chartSolidColor3;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" borderStyle="none">'
		+ '<Options>'
		+ '	<Legend defaultMouseOverAction="false" />'
		+ '</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '	<horizontalAxis>'
		+ '		<CategoryAxis id="hAxis" categoryField="name" padding="0.7"/>'
		+ '	</horizontalAxis>'
		+ '	<verticalAxis>'
		+ '		<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="kWh"/>'
		+ '	</verticalAxis>'
		+ '	<series>'
		+ '	<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '	<series>'
		+ '	<Column2DSeries yField="prvyyPwcsp" displayName="' + (Number(endDate.substr(0, 4)) - 1) + "년" + endDate.substr(4, 2) + '월(kWh)">'
		+ '		<fill>'
		+ '			<SolidColor color="' + solidColor1 + '"/>'
		+ '		</fill>'
		+ '		<showDataEffect>'
		+ '			<SeriesInterpolate />'
		+ '		</showDataEffect>'
		+ '	</Column2DSeries>'
		+ '	<Column2DSeries yField="thsyyPwcsp" displayName="' + endDate.substr(0, 4) + "년" + endDate.substr(4, 2) + '월(kWh)">'
		+ '		<fill>'
		+ '			<SolidColor color="' + solidColor2 + '"/>'
		+ '		</fill>'
		+ '		<showDataEffect>'
		+ '			<SeriesInterpolate />'
		+ '		</showDataEffect>'
		+ '	</Column2DSeries>'
		+ '	</series>'
		+ '	</Column2DSet>'
		+ '		<Line2DSeries yField="redcnRt" radius="4.5" itemRenderer="CircleItemRenderer" displayName="증감률(%)" labelPosition="up">'
		+ '			<stroke>'
		+ '				<Stroke color="#F9BD03" weight="3"/>'
		+ '			</stroke>'
		+ '		<lineStroke>'
		+ '			<Stroke color="#F9BD03" weight="3"/>'
		+ '		</lineStroke>'
		+ '		<verticalAxis>'
		+ '			<LinearAxis id="vAxis2" formatter="{numFmt}" title="%"/>'
		+ '		</verticalAxis>'
		+ '			<showDataEffect>'
		+ '				<SeriesInterpolate/>'
		+ '			</showDataEffect>'
		+ '		</Line2DSeries>'
		+ '	</series>'
		+ '	<verticalAxisRenderers>'
		+ '		<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		<Axis2DRenderer axis="{vAxis2}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '	</verticalAxisRenderers>'
		+ '	<horizontalAxisRenderers>'
		+ '		<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
		+ '	</horizontalAxisRenderers>'
		+ '</Combination2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm = spnSubTitle.getValue();
	// 엑셀 내부 타이틀 추가_240105
	var infoArr = [];
	var infoObj = {
		rowIndex 	: 0,
		colIndex 	: 0,
		rowSpan 	: 0,
		colSpan 	: 6,
		text 		: `${menuNm}_` + `${subTitleNm}`,
		textAlign 	: "left"
	};
	infoArr.push(infoObj);

	comLib.downloadExcel(grdPrvyySammVersusCnsmpSttusList, {
		fileName : `${menuNm}_` + `${subTitleNm}.xlsx`,
		type : 1,
		autoSizeColumn : true,
		useDataFormat: true,
		applyDataFormat : true
	}, infoArr);
};
